import{_ as a,o,c as t,ag as i}from"./chunks/framework.35uRI6hY.js";const g=JSON.parse('{"title":"Changelog","description":"","frontmatter":{},"headers":[],"relativePath":"changelog.md","filePath":"changelog.md"}'),l={name:"changelog.md"};function d(c,e,n,r,s,u){return o(),t("div",null,[...e[0]||(e[0]=[i('<h1 id="changelog" tabindex="-1">Changelog <a class="header-anchor" href="#changelog" aria-label="Permalink to &quot;Changelog&quot;">​</a></h1><p>All notable changes to this project will be documented in this file.</p><h2 id="_0-1-4-2026-03-02" tabindex="-1">[0.1.4] - 2026-03-02 <a class="header-anchor" href="#_0-1-4-2026-03-02" aria-label="Permalink to &quot;[0.1.4] - 2026-03-02&quot;">​</a></h2><h3 id="added" tabindex="-1">Added <a class="header-anchor" href="#added" aria-label="Permalink to &quot;Added&quot;">​</a></h3><ul><li>Per-action handler registry — define API calls per mutation instead of a central switch-case</li><li>Mutation state tracking — <code>status</code>, <code>isLoading</code>, <code>isQueued</code>, <code>isSuccess</code>, <code>isError</code>, <code>error</code>, <code>reset()</code></li><li><code>onSuccess</code> callback — fires only after a successful direct API call (online)</li><li>React Query integration — use <code>mutateAsync</code> from <code>useMutation</code> inside handlers</li><li>Network status via <code>useSyncExternalStore</code> — zero cascading re-renders</li><li>38 unit tests with Jest</li><li>GitHub Actions CI (Node 18 + 20)</li><li>Technology badges, MIT license, and CHANGELOG</li></ul><h3 id="changed" tabindex="-1">Changed <a class="header-anchor" href="#changed" aria-label="Permalink to &quot;Changed&quot;">​</a></h3><ul><li><code>OfflineProvider</code> no longer uses React Context — reads from singleton store</li><li><code>useNetworkStatus</code> migrated from <code>useContext</code> to <code>useSyncExternalStore</code></li><li>Improved docs with React Query examples and state flow tables</li></ul><h3 id="fixed" tabindex="-1">Fixed <a class="header-anchor" href="#fixed" aria-label="Permalink to &quot;Fixed&quot;">​</a></h3><ul><li>Handler persistence — per-action handlers survive component unmount</li></ul><h2 id="_0-1-0-2026-02-28" tabindex="-1">[0.1.0] - 2026-02-28 <a class="header-anchor" href="#_0-1-0-2026-02-28" aria-label="Permalink to &quot;[0.1.0] - 2026-02-28&quot;">​</a></h2><h3 id="added-1" tabindex="-1">Added <a class="header-anchor" href="#added-1" aria-label="Permalink to &quot;Added&quot;">​</a></h3><ul><li>Initial release</li><li><code>OfflineProvider</code> component with NetInfo integration</li><li><code>useOfflineMutation</code> hook for queue-aware mutations</li><li><code>useOfflineQueue</code> hook with <code>useSyncExternalStore</code></li><li><code>useSyncProgress</code> hook for live sync tracking</li><li><code>useNetworkStatus</code> hook for connectivity status</li><li><code>OfflineManager</code> singleton for direct API access</li><li>Storage adapters: MMKV, AsyncStorage, Memory</li><li>Realm adapter (record-based)</li><li>Custom storage adapter interface</li><li>Auto and manual sync modes</li><li><code>onOnlineRestore</code> callback with Alert, Toast, BottomSheet examples</li><li>Background sync support</li></ul>',12)])])}const f=a(l,[["render",d]]);export{g as __pageData,f as default};
